extension.valueString:
/*
@internal: Potential contraindications observations
*/
define "Potential contraindications":
  ([Observation: Concepts."Potential contraindications"]).complete()

/*
@internal: Observation for currently pregnant
*/
define "CI Currently pregnant Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Currently pregnant"

/*
@internal: Condition for currently pregnant
*/
define "CI Currently pregnant Condition":
  [Condition: Concepts."CI-Currently pregnant"]

/*
@internal: Condition for currently pregnant
*/
define "CI Currently pregnant Condition":
  Elements."CI Currently pregnant Condition" C
    where C.prevalenceInterval() includes Today

define "Pregnancy Status Observation":
  [Observation: Concepts."Pregnancy status"] O
    where O.status in { 'final', 'amended', 'corrected' }

/*
@input: The client is pregnant
@pseudocode: "Potential contraindications" = "Currently pregnant"
*/
define "The client is pregnant":
  exists "CI Currently pregnant Observation"
  or exists "CI Currently pregnant Condition"
  or exists WE."Pregnant Observation"

/*
@input: The client is currently pregnant
@pseudocode: "Potential contraindications" = "Currently pregnant"
@code: The client is currently pregnant-52
@decision: IMMZ.D5.DT.Varicella contraindications
*/
define "The client is currently pregnant":
  Encounter."The client is pregnant"

/*
@output: Varicella vaccination is contraindicated
@pseudocode: "Immunization recommendation status" = "Contraindicated"
*/
define "Varicella vaccination is contraindicated":
  Encounter."The client is currently pregnant"

/*
@output: Varicella vaccination is contraindicated Guidance
@guidance: Do not vaccinate client with varicella as varicella vaccination is contraindicated for pregnant client.
*/
define "Varicella vaccination is contraindicated Guidance":
  'Do not vaccinate client with varicella as varicella vaccination is contraindicated for pregnant client.'

/*
@internal: Observation for Planning to get pregnant in the next month
*/
define "CI Planning to get pregnant in the next month Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Planning to get pregnant in the next month"

/*
@internal: Observation for Planning to get pregnant in the next month
*/
define "CI Planning to get pregnant in the next month Observation":
  Elements."CI Planning to get pregnant in the next month Observation".encounterOrOnBefore(EncounterId, Today)

/*
@internal: Condition for Planning to get pregnant in the next month
*/
define "CI Planning to get pregnant in the next month Condition":
  [Condition: Concepts."CI-Planning to get pregnant in the next month"]

/*
@internal: Condition for Planning to get pregnant in the next month
*/
define "CI Planning to get pregnant in the next month Condition":
  Elements."CI Planning to get pregnant in the next month Condition" C
    where C.prevalenceInterval() includes Today

/*
@input: The client is planning to get pregnant in next month
@pseudocode: "Potential contraindications" = "Planning to get pregnant in the next month"
*/
define "The client is planning to get pregnant in next month":
  exists "CI Planning to get pregnant in the next month Observation"
    or exists "CI Planning to get pregnant in the next month Condition"

/*
@input: The client is planning to get pregnant in the next month
@pseudocode: "Potential contraindications" = "Planning to get pregnant in the next month"
@code: The client is planning to get pregnant in the next month-76
@decision: IMMZ.D5.DT.Varicella contraindications
*/
define "The client is planning to get pregnant in the next month":
  Encounter."The client is planning to get pregnant in next month"

/*
@output: Clinical judgement is required. Create clinical note Case 1
@pseudocode: "Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note Case 1":
  Encounter."The client is planning to get pregnant in the next month"

/*
@internal: Immunocompromised Observation
*/
define "Immunocompromised Observation":
  ([Observation: Concepts."Immunocompromised"] O
    sort by end of effective.toInterval() desc).complete()

/*
@input: Client is immunocompromised
@pseudocode: "Immunocompromised" = TRUE
*/
define "Client is immunocompromised":
  exists( "Immunocompromised Observation" ) and
  First( "Immunocompromised Observation" ).value = true

/*
@internal: Observation for Immunocompromised
*/
define "CI Immunocompromised Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Immunocompromised"

/*
@internal: Observation for Immunocompromised
*/
define "CI Immunocompromised Observation":
  Elements."CI Immunocompromised Observation".encounterOrOnBefore(EncounterId, Today)

/*
@internal: Condition for Immunocompromised
*/
define "CI Immunocompromised Condition":
  [Condition: Concepts."CI-Immunocompromised"]

/*
@internal: Condition for Immunocompromised
*/
define "CI Immunocompromised Condition":
  Elements."CI Immunocompromised Condition" C
    where C.prevalenceInterval() includes Today

/*
@input: The client is immunocompromised
@pseudocode: "Potential contraindications" = "Immunocompromised"
*/
define "The client is immunocompromised":
  "Client is immunocompromised"
    or exists "CI Immunocompromised Observation"
    or exists "CI Immunocompromised Condition"

/*
@input: The client is immunocompromised
@pseudocode: "Potential contraindications" = "Immunocompromised"
@code: The client is immunocompromised-51
@decision: IMMZ.D5.DT.Varicella contraindications
*/
define "The client is immunocompromised":
  Encounter."The client is immunocompromised"

/*
@output: Clinical judgement is required. Create clinical note Case 2
@pseudocode: '"Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note Case 2":
  Encounter."The client is immunocompromised"

/*
@internal: Observation for Exposed to immunosuppressive treatment
*/
define "CI Exposed to immunosuppressive treatment Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Exposed to immunosuppressive treatment"

/*
@internal: Observation for Exposed to immunosuppressive treatment
*/
define "CI Exposed to immunosuppressive treatment Observation":
  Elements."CI Exposed to immunosuppressive treatment Observation".encounterOrOnBefore(EncounterId, Today)

/*
@internal: Condition for Exposed to immunosuppressive treatment
*/
define "CI Exposed to immunosuppressive treatment Condition":
  [Condition: Concepts."CI-Exposed to immunosuppressive treatment"]

/*
@internal: Condition for Exposed to immunosuppressive treatment
*/
define "CI Exposed to immunosuppressive treatment Condition":
  Elements."CI Exposed to immunosuppressive treatment Condition" C
    where C.prevalenceInterval() includes Today

/*
@input: The client is exposed to immunosuppressive treatment
@pseudocode: "Potential contraindications" = "Exposed to immunosuppressive treatment"
*/
define "The client is exposed to immunosuppressive treatment":
  exists "CI Exposed to immunosuppressive treatment Observation"
    or exists "CI Exposed to immunosuppressive treatment Condition"

/*
@input: The client is receiving or has received medications that may be immunosuppressive
@pseudocode: "Potential contraindications" = "Exposed to immunosuppressive treatment"
@code: The client is receiving or has received medications that may be immunosuppressive-72
@decision: IMMZ.D5.DT.Varicella contraindications
*/
define "The client is receiving or has received medications that may be immunosuppressive":
  Encounter."The client is exposed to immunosuppressive treatment"

/*
@output: Clinical judgement is required. Create clinical note Case 3
@pseudocode: "Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note Case 3":
  Encounter."The client is receiving or has received medications that may be immunosuppressive"

/*
@output: Clinical judgement is required. Create clinical note
@pseudocode: "Immunization recommendation status" = "Further evaluation needed"
*/
define "Clinical judgement is required. Create clinical note":
  "Clinical judgement is required. Create clinical note Case 1"
    or "Clinical judgement is required. Create clinical note Case 2"
    or "Clinical judgement is required. Create clinical note Case 3"

/*
@output: Clinical judgement is required. Create clinical note Guidance
@guidance = Discuss pregnancy intentions, consider risks of vaccination and make a clinical judgement. It is recommended to delay pregnancy for 4 weeks after vaccination.
@guidance = Client is immunocompromised, consider risks of vaccination and make a judgement. Consider 2 dose schedule.
@guidance = Client is receiving or has received medications that may be immunosuppressive, consider risks of vaccination and make a judgement.
*/
define "Clinical judgement is required. Create clinical note Guidance":
  case
    when "Clinical judgement is required. Create clinical note Case 1" then 'Discuss pregnancy intentions, consider risks of vaccination and make a clinical judgement. It is recommended to delay pregnancy for 4 weeks after vaccination.'
    when "Clinical judgement is required. Create clinical note Case 2" then 'Client is immunocompromised, consider risks of vaccination and make a judgement. Consider 2 dose schedule.'
    when "Clinical judgement is required. Create clinical note Case 3" then 'Client is receiving or has received medications that may be immunosuppressive, consider risks of vaccination and make a judgement.'
    else ''
  end

/*
@internal: Observation for Immunodeficiency syndromes
*/
define "CI Immunodeficiency syndromes Observation":
  "Potential contraindications" O
